// input: { success: true, links: [ { url: "..." } ] }

const links = $json.links || [];
const seen = new Set();

const blockedKeywords = [
  "/press-blog",
  "/newsletter",
  "/assets-vault",
  "press",
  "gallery",
  "project",
  "newsletter"
];

return links
  .filter(link => {
    let url = link.url;
    if (!url) return false;

    // ❌ Remove blocked keywords
    for (const keyword of blockedKeywords) {
      if (url.includes(keyword)) return false;
    }

    // ❌ Remove XML files
    if (url.includes(".xml")) return false;

    // 🔄 Normalize trailing slash
    url = url.endsWith("/") ? url.slice(0, -1) : url;

    // ❌ Remove duplicates
    if (seen.has(url)) return false;
    seen.add(url);

    // Save normalized URL back
    link.url = url;
    return true;
  })
  .map(link => {
    return {
      url: link.url
    };
  });

const html = $json.html;

// VERY simple cleaner (replace later with readability)
const text = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

return {
  url: $json.url,
  project_id: $json.project_id,
  text
};

const raw = $json.text || "";
const text = raw.replace(/\s+/g, " ").trim(); // clean whitespace
const chunkSize = 1000;
const overlap = 200;

const chunks = [];
let i = 0;

while (i < text.length) {
  const chunk = text.slice(i, i + chunkSize).trim();

  // Only save useful chunks
  if (chunk.length > 50) {
    chunks.push({
      content: chunk,
      url: $json.url,
      project_id: $json.project_id
    });
  }

  i += chunkSize - overlap;
}

return chunks;
